import React, { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import { useAuth } from "../context/AuthContext";


export default function OAuthCallback() {
  const [params]   = useSearchParams();
  const { login }  = useAuth();
  const navigate   = useNavigate();
  const [status, setStatus] = useState("Completing sign-in…");
  const [error, setError]   = useState("");

  useEffect(() => {
    const token = params.get("token");
    const err   = params.get("error");

    if (err) {
      setError("OAuth sign-in failed. " + (err === "oauth_not_configured" ? "OAuth credentials not configured in backend .env file." : "Please try again or use email/password."));
      setTimeout(() => navigate("/login"), 3500);
      return;
    }

    if (!token) {
      setError("No token received. Redirecting to login…");
      setTimeout(() => navigate("/login"), 2500);
      return;
    }

    setStatus("Fetching your profile…");
    // Decode JWT to get user info (we need to call /me)
    fetch("http://localhost:5000/api/auth/me", {
      headers: { Authorization: `Bearer ${token}` }
    })
      .then(r => r.json())
      .then(data => {
        if (data.user) {
          login(data.user, token);
          setStatus("Success! Redirecting…");
          setTimeout(() => navigate("/dashboard"), 600);
        } else {
          throw new Error("No user data");
        }
      })
      .catch(() => {
        setError("Sign-in failed. Please try again.");
        setTimeout(() => navigate("/login"), 2500);
      });
  }, []);

  return (
    <div style={{ minHeight:"100vh", background:"var(--bg)", color:"var(--text)", display:"flex", alignItems:"center", justifyContent:"center" }}>
      <div style={{ textAlign:"center", maxWidth:360 }}>
        <img src='/skill.jpg' alt="SkillGraph AI"
          style={{ width:64, height:64, borderRadius:16, objectFit:"cover", marginBottom:"1.5rem", border:"2px solid rgba(61,142,240,.4)" }} />

        {error ? (
          <>
            <div style={{ fontSize:"2rem", marginBottom:".8rem" }}>⚠️</div>
            <h2 style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, marginBottom:".6rem", color:"var(--red)" }}>Sign-in Failed</h2>
            <p style={{ color:"var(--muted)", fontSize:".88rem", lineHeight:1.6 }}>{error}</p>
          </>
        ) : (
          <>
            <div style={{ width:40, height:40, border:"3px solid var(--border)", borderTopColor:"var(--blue)", borderRadius:"50%", animation:"spin .7s linear infinite", margin:"0 auto 1.2rem" }} />
            <h2 style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, marginBottom:".5rem" }}>Signing you in…</h2>
            <p style={{ color:"var(--muted)", fontSize:".88rem" }}>{status}</p>
          </>
        )}
      </div>
    </div>
  );
}
